<?php include 'header.php';
if(!isset($_SESSION['cart'])) $_SESSION['cart']=[]; if(!isset($_SESSION['sizes'])) $_SESSION['sizes']=[];
if(($_GET['action']??'')==='add' && $_SERVER['REQUEST_METHOD']==='POST'){ $id=(int)$_POST['id']; $qty=max(1,(int)$_POST['qty']); $_SESSION['cart'][$id]=($_SESSION['cart'][$id]??0)+$qty; $_SESSION['sizes'][$id]=$_POST['size']??''; header('Location: cart.php'); exit; }
if(($_GET['action']??'')==='remove'){ unset($_SESSION['cart'][(int)$_GET['id']],$_SESSION['sizes'][(int)$_GET['id']]); header('Location: cart.php'); exit; }
$items=[];$total=0; if($_SESSION['cart']){ $ids=array_keys($_SESSION['cart']); $in=implode(',',array_fill(0,count($ids),'?')); $st=$pdo->prepare("SELECT * FROM products WHERE id IN ($in)"); $st->execute($ids); $items=$st->fetchAll(); }
?>
<section class="section"><div class="section-title"><h2>Giỏ hàng</h2></div><?php if(!$items): ?><div class="cart-empty">Giỏ hàng trống<br><br><a class="btn" href="products.php">Mua sắm ngay</a></div><?php else: ?><table class="table"><tr><th>Sản phẩm</th><th>Size</th><th>SL</th><th>Giá</th><th>Tổng</th><th></th></tr><?php foreach($items as $p): $qty=$_SESSION['cart'][$p['id']]; $price=productPrice($p); $sum=$qty*$price; $total+=$sum; ?><tr><td><?=$p['name']?></td><td><?=$_SESSION['sizes'][$p['id']]??''?></td><td><?=$qty?></td><td><?=money($price)?></td><td><?=money($sum)?></td><td><a data-confirm="Xóa sản phẩm?" href="cart.php?action=remove&id=<?=$p['id']?>">Xóa</a></td></tr><?php endforeach; ?><tr><th colspan="4">Tổng cộng</th><th><?=money($total)?></th><th></th></tr></table><br><a class="btn" href="checkout.php">Thanh toán</a><?php endif; ?></section><?php include 'footer.php'; ?>
